class PortfolioCard extends React.Component {
    constructor(props) {
        super(props)
    }
  render() {
    const settings = {
        dots: true,
        infinite: true,
        speed: 500,
        slidesToShow: 1,
        slidesToScroll: 1
      };
    return (
        <>
            <Container style={{width:"100%"}}>
                <div>
                    <h2> Single Item</h2>
                    <Slider {...settings}>
                    <div>
                        <h3>1</h3>
                    </div>
                    <div>
                        <h3>2</h3>
                    </div>
                    <div>
                        <h3>3</h3>
                    </div>
                    <div>
                        <h3>4</h3>
                    </div>
                    <div>
                        <h3>5</h3>
                    </div>
                    <div>
                        <h3>6</h3>
                    </div>
                    </Slider>
                </div>

                <Card style={{background: '#D9DDE2', marginBottom: "10px"}}>
                <Row>
                    <Col>
                    <Card.Img variant="top" src={this.props.image}/>
                    </Col>
                    <Col>
                    <Card.Body>
                    <Card.Title className="text-muted"><h1>{this.props.film}</h1></Card.Title>
                    <p>{this.props.reviewp1}</p>
                    <p>{this.props.reviewp2}</p>
                    <p>{this.props.reviewp3}</p>
                    <p>{this.props.reviewp4}</p>
                    <p>{this.props.reviewp5}</p>
                    </Card.Body>
                    </Col>
                    </Row>
                    <Card.Footer>
                    <div style={{textAlign: "center"}}>
                        <small>Written: {this.props.date}</small>
                    </div>
                    <div style={{textAlign: "center"}}>
                        <small>Image: {this.props.url}</small>
                    </div>
                    </Card.Footer>

                </Card>

            </Container>
        </>
    )
  }
}

export default PortfolioCard
